// Filter profiles by follower count and recency, then map to outreach tracker columns
const MIN_FOLLOWERS = 500;
const MAX_FOLLOWERS = 5000;
const MAX_DAYS_SINCE_LAST_POST = 21;

const results = [];
const now = new Date();

for (const item of $input.all()) {
  const profile = item.json;

  if (!profile.username) continue;

  const followers = profile.followersCount || profile.followers || 0;
  if (followers < MIN_FOLLOWERS || followers > MAX_FOLLOWERS) continue;

  // Recency filter — skip accounts with no post in the last 21 days
  const lastPostRaw = profile.latestIgtvVideo?.timestamp ||
                      profile.latestPost?.timestamp ||
                      profile.postsTimelineList?.[0]?.timestamp || '';
  if (lastPostRaw) {
    const daysSincePost = (now - new Date(lastPostRaw)) / (1000 * 60 * 60 * 24);
    if (daysSincePost > MAX_DAYS_SINCE_LAST_POST) continue;
  } else {
    continue;
  }

  const lastPostDate = new Date(lastPostRaw).toISOString().split('T')[0];

  const category = (profile.businessCategoryName || '').toLowerCase();
  const bio = (profile.biography || '').toLowerCase();

  let type = 'Other';
  if (category.includes('restaurant') || category.includes('cafe') || category.includes('food') ||
      bio.includes('restaurant') || bio.includes('cafe') || bio.includes('coffee')) {
    type = 'Restaurant / Cafe';
  } else if (category.includes('beauty') || category.includes('aesthetic') || category.includes('clinic') ||
             category.includes('skin') || bio.includes('aesthetic') || bio.includes('beauty clinic') ||
             bio.includes('skin clinic')) {
    type = 'Beauty / Aesthetics';
  }

  let location = 'London';
  const locationMatch = bio.match(/([a-z\s]+),?\s*london/i) || bio.match(/london[,\s]+([a-z\s]+)/i);
  if (locationMatch) {
    location = locationMatch[0].trim().replace(/\n/g, ' ').substring(0, 50);
  }

  results.push({
    json: {
      'Business Name': profile.fullName || profile.username,
      'Type': type,
      'Location': location,
      'Instagram Handle': '@' + profile.username,
      'Followers': followers,
      'Last Post': lastPostDate,
      'Problem Identified': '',
      'First Contact Date': '',
      'Channel': 'Instagram DM',
      'Message Sent': '',
      'Response': '',
      'Status': 'New Lead',
      'Follow Up Date': '',
      'Notes': (profile.biography || '').substring(0, 150)
    }
  });
}

const seen = new Set();
return results.filter(r => {
  const h = r.json['Instagram Handle'].toLowerCase();
  if (seen.has(h)) return false;
  seen.add(h);
  return true;
});

// Merge real profile bios and follower counts into the filtered lead list
// Falls back to post caption if no bio found
const filteredLeads = $('Filter & Format Leads').all();
const profileResults = $input.all();

// Build a map of username -> profile data for O(1) lookup
const profileMap = {};
for (const item of profileResults) {
  const p = item.json;
  const username = (p.username || p.inputUrl || '').toLowerCase().replace('@', '');
  if (username) {
    profileMap[username] = {
      bio: p.biography || p.description || '',
      followers: p.followersCount || p.followers || null
    };
  }
}

const merged = filteredLeads.map(lead => {
  const handle = (lead.json['Instagram Handle'] || '').replace('@', '').toLowerCase();
  const profile = profileMap[handle];

  let notes = lead.json['Notes'] || '';
  let followers = lead.json['Followers'];

  if (profile) {
    if (profile.bio && profile.bio.trim()) {
      notes = profile.bio.substring(0, 150);
    } else if (!notes) {
      notes = 'Check manually — no bio returned';
    }
    if (profile.followers !== null) {
      followers = profile.followers;
    }
  } else {
    notes = notes || 'Check manually — profile not found in scrape';
  }

  return {
    json: {
      ...lead.json,
      'Notes': notes,
      'Followers': followers
    }
  };
});

return merged;

// Deduplicate against existing sheet rows using Instagram Handle
// Must reference Merge Profile Data — not Filter & Format Leads
const newLeads = $('Merge Profile Data').all();
const existingRows = $('Get Existing Leads').all();

const existingHandles = new Set(
  existingRows.map(r => (r.json['Instagram Handle'] || '').toLowerCase())
);

const fresh = newLeads.filter(lead => {
  const handle = (lead.json['Instagram Handle'] || '').toLowerCase();
  return handle && !existingHandles.has(handle);
});

console.log('Fresh leads: ' + fresh.length + ' of ' + newLeads.length + ' total scraped');
return fresh;
